package github.chains;

import spoon.Launcher;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;
import spoon.template.Template;
import spoon.template.TemplateParameter;
import spoon.template.Substitution;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // This is a generic transformation for fixing API changes in sonarlint-core
        // Specifically targeting the change from addEnabledLanguages to addAllEnabledLanguages

        Launcher launcher = new Launcher();
        launcher.addInputResource("/workspace/sorald");
        launcher.setSourceOutputDirectory("/workspace/sorald-fixed");
        launcher.getEnvironment().setComplianceLevel(8);

        // Build the model
        launcher.buildModel();

        Factory factory = launcher.getFactory();

        // Find all invocations of addEnabledLanguages method
        List<CtInvocation> invocations = factory.getModel().getElements(
            new TypeFilter<>(CtInvocation.class) {
                @Override
                public boolean matches(CtInvocation element) {
                    return element.getMethod().getSimpleName().equals("addEnabledLanguages") &&
                           element.getTarget() != null &&
                           element.getTarget().getType().getQualifiedName().contains("AnalysisEngineConfiguration$Builder");
                }
            }
        );

        // Replace with addAllEnabledLanguages if it exists, otherwise with individual calls
        for (CtInvocation invocation : invocations) {
            // Get the method reference
            CtExecutableReference methodRef = invocation.getMethod();

            // Create new invocation with the correct method name
            CtInvocation newInvocation = factory.Code().createInvocation(
                invocation.getTarget(),
                factory.Executable().createReference(
                    methodRef.getDeclaringType(),
                    "addAllEnabledLanguages",
                    methodRef.getActualTypeArguments()
                ),
                invocation.getArguments()
            );

            // Replace the old invocation with the new one
            invocation.replace(newInvocation);
        }

        // Write the modified code
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation completed. Fixed " + invocations.size() + " occurrences.");
    }
}

